I've added the logic for finding the source, but couldn't come up with answer to the follow up, i.e. return the longest route possible.

Please find my code below and let me know what changes can be made to achieve this

```
/**
* current output
* JFK SFO ATL CDG DXB 
* 
* Expected output
* JFK SFO ATL CDG MAA ORD DFW 
*/
public class Main {    
    private static List<String> findItinerary(List<List<String>> tickets) {
        Map<String,LinkedList<String>> map = new HashMap<>();
        Map<String, Integer> incountMap = new HashMap<>();

        for(List<String> ticket:tickets) {
            String src = ticket.get(0);
            map.put(src,new LinkedList<>());
            incountMap.put(src, 0);
        }

        for(List<String> ticket:tickets) {
            String src = ticket.get(0);
            String dst = ticket.get(1);
            map.get(src).add(dst);
            incountMap.put(dst, incountMap.getOrDefault(dst,0)+1);
        }

        String source = "";
        for(String src:incountMap.keySet()) {
            if(incountMap.get(src) == 0) source = src;
        }
        LinkedList<String> result = new LinkedList<>();
        backtrack(source, result, map);
        return result;
    }

    private static void backtrack(String source, LinkedList<String> result,  Map<String,LinkedList<String>> map) {
        if(map.containsKey(source)) {
            LinkedList<String> list = map.get(source);
            if(!list.isEmpty()) {
                String dst = list.pollFirst();
                backtrack(dst,result,map);
            }
        }
        result.addFirst(source);
    }

    public static void main(String[] args) {
        // [["JFK","SFO"],["ATL","CDG"],["SFO","ATL"],["CDG","MAA"],["MAA","ORD"],["ORD","DFW"],["CDG","DXB"]]
        List<List<String>> tickets = Arrays.asList(
            Arrays.asList("JFK","SFO"),
            Arrays.asList("ATL","CDG"),
            Arrays.asList("SFO","ATL"),
            Arrays.asList("CDG","DXB"),
            Arrays.asList("CDG","MAA"),
            Arrays.asList("MAA","ORD"),
            Arrays.asList("ORD","DFW")

        );
        findItinerary(tickets).forEach(x -> System.out.println(x));
    }
}
